











































































































import Vue from 'vue';
import { WorkspaceDataModel } from '@/apis/models/WorkspaceModel';
import {
  Permission, ResourceType, ShareMapping, ShareMappingUpdatePayload,
} from '@/apis/models/ShareMappingModel';
import MemberGroupApi from '@/apis/MemberGroupApi';
import QuizGroupApi from '@/apis/QuizGroupApi';
import ShareMappingApiModule from '@/apis/ShareMappingApiModule';

const MODAL_WIDTH = 640;
export default Vue.extend({
  data() {
    return {
      modalWidth: MODAL_WIDTH,
      shareMappings: [] as ShareMapping[],
      userInput: {
        search: '',
        searchState: null as null | boolean,
        permission: Permission.DETAIL_VIEWER,
      },
      permissionOptions: Object.keys(Permission),

      resourceType: null as null | ResourceType,
      resourceId: '',
      shareApi: null as null | ShareMappingApiModule,
    };
  },
  computed: {
    currentWorkspace(): WorkspaceDataModel {
      return this.$store.state.currentWorkspace;
    },
  },
  created() {
    this.modalWidth = window.innerWidth < MODAL_WIDTH ? MODAL_WIDTH / 2 : MODAL_WIDTH;
  },
  methods: {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    beforeOpen(event: any) {
      this.shareMappings = [] as ShareMapping[];
      this.userInput = {
        search: '',
        searchState: null as null | boolean,
        permission: Permission.DETAIL_VIEWER,
      };

      this.resourceId = event.params.resourceId;

      switch (event.params.resourceType) {
        case ResourceType.MEMBER_GROUP:
          this.shareApi = MemberGroupApi.share;
          break;
        case ResourceType.QUIZ_GROUP:
          this.shareApi = QuizGroupApi.share;
          break;
        default:
          console.error(`Invalid resource type: ${this.resourceType}`);
      }

      this.loadShareMappings();
    },
    loadShareMappings() {
      if (this.shareApi) {
        this.shareApi.list(this.currentWorkspace.uuid, this.resourceId).then((shareMappings) => {
          this.shareMappings = shareMappings;
        });
      }
    },
    createShareMapping() {
      if (this.shareApi) {
        this.userInput.searchState = null;
        this.shareApi.create(this.currentWorkspace.uuid, this.resourceId, this.userInput.search, this.userInput.permission).then((shareMapping) => {
          this.shareMappings.push(shareMapping);
          this.userInput.searchState = true;
          this.userInput.search = '';
        }).catch((error) => {
          if (error.response && error.response.status) {
            if (error.response.status === 404) {
              this.userInput.searchState = false;
            }
          }
        });
      }
    },
    updateShareMapping(shareMapping: ShareMapping, option: Permission) {
      if (this.shareApi) {
        const payload = new ShareMappingUpdatePayload(option);
        this.shareApi.update(this.currentWorkspace.uuid, this.resourceId, shareMapping.uuid, payload).then((updatedShareMapping) => {
          shareMapping.permission = updatedShareMapping.permission;
        });
      }
    },
    deleteShareMapping(index: number) {
      if (this.shareApi) {
        this.shareApi.destroy(this.currentWorkspace.uuid, this.resourceId, this.shareMappings[index].uuid).then(() => {
          this.shareMappings.splice(index, 1);
        });
      }
    },
    handleFinish() {
      this.$modal.hide('manage-share-mapping-modal');
    },
    translatePermission(permission: Permission): string {
      switch (permission) {
        case Permission.EDITOR:
          return '編輯者';
        case Permission.DETAIL_VIEWER:
          return '檢視者';
        case Permission.GENERAL_VIEWER:
          return '使用者';
        default:
          return '無權限';
      }
    },
  },
});
